## 8. Auth Server — `/home/aditya/projects/alpauls-ats/src/lib/auth/server.ts`

```ts
import { drizzleAdapter } from "@better-auth/drizzle-adapter";
import { type BetterAuthOptions, betterAuth } from "better-auth";
import { APIError } from "better-auth/api";
import { admin, customSession, phoneNumber } from "better-auth/plugins";
import { tanstackStartCookies } from "better-auth/tanstack-start";
import { eq } from "drizzle-orm";

import {
  ac,
  type RoleCode,
  resolvePermissions,
  roles,
} from "@/lib/auth/access-control";
import { db } from "@/lib/db/server";
import * as schema from "@/schema";

const options = {
  database: drizzleAdapter(db, { provider: "pg", schema }),
  databaseHooks: {
    user: {
      create: {
        before: async (_user, ctx) => {
          const path = ctx?.path ?? "";
          if (path === "/admin/create-user") return;
          throw new APIError("BAD_REQUEST", { message: "Signups are disabled" });
        },
      },
    },
  },
  emailAndPassword: { enabled: false },
  plugins: [
    phoneNumber({
      sendOTP: async ({ phoneNumber: phone, code }) => {
        const [existingUser] = await db.select().from(schema.user).where(eq(schema.user.phoneNumber, phone));
        if (!existingUser) throw new APIError("BAD_REQUEST", { message: "No account found" });
        if (existingUser.banned) throw new APIError("FORBIDDEN", { message: "Account is suspended" });
        console.log(`[OTP] Phone: ${phone} | Code: ${code}`);
      },
    }),
    admin({ ac, roles }),
    tanstackStartCookies(),
  ],
  session: { expiresIn: 60 * 60 * 24 * 30 },
  user: {
    additionalFields: {
      permissions: { defaultValue: null, input: false, required: false, type: "json" },
      supervisorId: { defaultValue: null, input: false, required: false, type: "string" },
    },
  },
} satisfies BetterAuthOptions;

export const auth = betterAuth({
  ...options,
  plugins: [
    customSession(async ({ user, session }) => {
      const role = (user.role ?? "custom") as RoleCode;
      const permissions = resolvePermissions({ permissions: user.permissions, role });
      return { session, user: { ...user, permissions, role } };
    }, options),
    ...(options.plugins ?? []),
  ],
});
```

**Key observations**:
- Self-registration is blocked (only `/admin/create-user` path is allowed)
- `customSession` plugin injects `permissions` (resolved array) and `role` onto the user object in session
- Phone + OTP login only; email/password disabled
- Additional user fields: `permissions` (JSON), `supervisorId` (string)
- The `auth.$Infer.Session.user` type includes `permissions: string[]` and `role: RoleCode`

